const item = $json;

function separarMarcas(valor) {
  if (!valor) return [];
  return valor
    .toString()
    .split(';')
    .map(v => v.trim())
    .filter(v => v !== '');
}

const numeroItem = item['Item'] ?? item['A'] ?? '';
const descricao = item['Descrição'] ?? item['B'] ?? '';

const obrigatorias = separarMarcas(item['Marca obrigatória'] ?? item['C'] ?? '');
const preferencias = separarMarcas(item['Marca de preferencia'] ?? item['D'] ?? '');

let caminho = 'SEM_MARCA';

if (obrigatorias.length >= 2 && preferencias.length === 0) {

  caminho = 'DUAS_OBRIGATORIAS';

} else if (obrigatorias.length === 1 && preferencias.length === 0) {

  caminho = 'UMA_OBRIGATORIA';

} else if (preferencias.length >= 2 && obrigatorias.length === 0) {

  caminho = 'DUAS_PREFERENCIAIS';

} else if (preferencias.length === 1 && obrigatorias.length === 0) {

  caminho = 'UMA_PREFERENCIA';

} else if (obrigatorias.length === 1 && preferencias.length === 1) {

  caminho = 'UMA_OBRIGATORIA_UMA_PREFERENCIA';

} else {

  // qualquer outro caso cai aqui
  caminho = 'SEM_MARCA';

}

return [{
  json: {
    ...item,
    numero_item: numeroItem,
    descricao_item: descricao,
    caminho_logico: caminho,
    marcas_obrigatorias: obrigatorias,
    marcas_preferencia: preferencias
  }
}];

const item = $json;

const pergunta = `ITEM DO EDITAL: ${item.numero_item}\n\nESPECIFICAÇÃO:\n${item.descricao_item}\n\nOBJETIVO:\n- Encontrar um produto real disponível no Brasil que atenda à especificação.\n- Sem restringir marca.\n- Retorne a melhor opção inicial plausível.\n\nREGRAS:\n- Use fabricantes, distribuidores ou lojas brasileiras.\n- Não invente informações.\n- Responda SOMENTE em JSON.\n\n{\n  \"results\": [\n    {\n      \"Nome do Produto\": \"\",\n      \"Marca do Produto\": \"\",\n      \"Modelo do Produto\": \"\",\n      \"Descrição do produto\": \"\",\n      \"Link completo do anuncio (url completa)\": \"\",\n      \"Preço do produto\": null,\n      \"Pontos que atende à especificação\": [],\n      \"Pontos que não atende à especificação\": []\n    }\n  ]\n}`;

const body = {
  model: 'gpt-4o-mini-search-preview',
  web_search_options: {
    user_location: { type: 'approximate', approximate: { country: 'BR' } },
    search_context_size: 'high'
  },
  messages: [
    {
      role: 'system',
      content: 'Você é um especialista em compras públicas no Brasil. Busque produtos reais no mercado brasileiro.'
    },
    {
      role: 'user',
      content: pergunta
    }
  ]
};

return [{
  json: {
    ...item,
    sugestao_label: 'Sugestão 1',
    pergunta_gpt: pergunta,
    body_openai: body
  }
}];

const base = $node['5 - Ajuste dados primeira pergunta - Sugestão 1'].json;
const resp = $node['6 - Primeira consulta API - Sugestão 1'].json;

const promptTokens = resp.usage?.prompt_tokens ?? 0;
const completionTokens = resp.usage?.completion_tokens ?? 0;
const totalTokens = resp.usage?.total_tokens ?? 0;
const chamadasWeb = 1;

const USD_BRL = 5.0;
const USD_PER_1M_INPUT = 0.15;
const USD_PER_1M_OUTPUT = 0.60;
const USD_WEB_SEARCH_CALL = 0.025;

const custoInputUsd = (promptTokens * USD_PER_1M_INPUT) / 1000000;
const custoOutputUsd = (completionTokens * USD_PER_1M_OUTPUT) / 1000000;
const custoWebUsd = chamadasWeb * USD_WEB_SEARCH_CALL;
const custoTotalUsd = custoInputUsd + custoOutputUsd + custoWebUsd;
const custoTotalBrl = custoTotalUsd * USD_BRL;

const raw = resp.choices?.[0]?.message?.content ?? '';
const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

function extrairPrimeiroProduto(texto) {
  const start = texto.indexOf('{');
  const end = texto.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return null;
  try {
    const obj = JSON.parse(texto.slice(start, end + 1));
    const results = Array.isArray(obj.results) ? obj.results : [];
    for (const p of results) {
      const nome = (p['Nome do Produto'] ?? '').toString().trim();
      const marca = (p['Marca do Produto'] ?? '').toString().trim();
      const modelo = (p['Modelo do Produto'] ?? '').toString().trim();
      const link = (p['Link completo do anuncio (url completa)'] ?? '').toString().trim();
      if (nome || marca || modelo || link) {
        return {
          nome_produto: nome,
          marca: marca,
          modelo: modelo,
          descricao_produto: (p['Descrição do produto'] ?? '').toString().trim(),
          link: link,
          preco_brl: ('Preço do produto' in p) ? p['Preço do produto'] : null
        };
      }
    }
  } catch (e) {
    return null;
  }
  return null;
}

const melhor = extrairPrimeiroProduto(cleaned);

return [{
  json: {
    ...base,
    primeira_busca_raw: raw,
    produto_consulta_1: melhor,
    nome_produto: melhor?.nome_produto ?? '',
    marca: melhor?.marca ?? '',
    modelo: melhor?.modelo ?? '',
    descricao_produto: melhor?.descricao_produto ?? '',
    link: melhor?.link ?? '',
    preco_brl: melhor?.preco_brl ?? null,
