    tokens_busca_completion_total: completionTokens,
    tokens_busca_total: totalTokens,
    custo_busca_1_brl: custoTotalBrl,
    custo_busca_total_brl: custoTotalBrl,
    sugestao_gpt: 'Sugestão 1 GPT'
  }
}];

