  blocoProdutos += `
Produto 2
Marca: ${marcaB}
Modelo: ${modeloB}
`;
}

if (marcaC || modeloC) {
  blocoProdutos += `
Produto 3
Marca: ${marcaC}
Modelo: ${modeloC}
`;
}

// Prompt completo
const pergunta = `
Especificação do edital:
${descricao}

Entre os produtos a seguir, qual melhor atende a especificação?

Verifique detalhadamente cada requisito técnico.
Não invente informações.
Se nenhum atender completamente, escolha o que mais se aproxima tecnicamente.

${blocoProdutos}

Responda SOMENTE em JSON:

{
 "melhor_produto": "1, 2 ou 3",
 "justificativa": ""
}
`;

// Retorno para o node HTTP/OpenAI
return [{
  json: {
    ...$json,
    body_gpt: {
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content: "Você é especialista em análise técnica de produtos para licitações públicas no Brasil. Seja rigoroso e técnico."
        },
        {
          role: "user",
          content: pergunta
        }
      ],
      temperature: 0
    }
  }
}];
